import type { HTMLAttributes } from 'react';
export interface PaginationProps extends Omit<HTMLAttributes<HTMLUListElement>, 'onChange'> {
    /** Общее количество страниц */
    count: number;
    /** Признак, сокращённый / развёрнутый, влияет на количество отображаемых номеров страниц */
    collapsed?: boolean;
    /** Номер текущей страницы (начиная с 1) */
    page?: number;
    /** Событие смены номера страницы */
    onChange?: (index: number) => void;
    /** Количество отображаемых номеров страниц между номерами первой и последней страниц */
    siblingCount?: number;
}
